"""
Parameterized generator for GH1034_airflow_64145.

Source PR:    https://github.com/apache/airflow/pull/64145
Source Issue: N/A

Seed varies: renames 'above' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH1034_airflow_64145'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH1034_airflow_64145'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('above', 'above' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH1034_airflow_64145',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'apache/airflow',
                "pr_number": 64145,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/apache/airflow/pull/64145",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'airflow-core/src/airflow/utils/db_manager.py': '# Licensed to the Apache Software Foundation (ASF) under one\n# or more contributor license agreements.  See the NOTICE file\n# distributed with this work for additional information\n# regarding copyright ownership.  The ASF licenses this file\n# to you under the Apache License, Version 2.0 (the\n# "License"); you may not use this file except in compliance\n# with the License.  You may obtain a copy of the License at\n#\n#   http://www.apache.org/licenses/LICENSE-2.0\n#\n# Unless required by applicable law or agreed to in writing,\n# software distributed under the License is distributed on an\n# "AS IS" BASIS, WITHOUT WARRANTIES OR CONDITIONS OF ANY\n# KIND, either express or implied.  See the License for the\n# specific language governing permissions and limitations\n# under the License.\nfrom __future__ import annotations\n\nimport inspect as _inspect\nimport os\nfrom typing import TYPE_CHECKING\n\nfrom alembic import command\nfrom sqlalchemy import inspect\n\nfrom airflow import settings\nfrom airflow._shared.module_loading import import_string\nfrom airflow.configuration import conf\nfrom airflow.exceptions import AirflowException\nfrom airflow.utils.log.logging_mixin import LoggingMixin\nfrom airflow.utils.sqlalchemy import get_dialect_name\n\nif TYPE_CHECKING:\n    from alembic.script import ScriptDirectory\n    from sqlalchemy import MetaData\n\n\ndef _callable_accepts_use_migration_files(callable_) -> bool:\n    """Return True if *callable_* accepts a ``use_migration_files`` keyword argument."""\n    try:\n        signature = _inspect.signature(callable_)\n    except (TypeError, ValueError):\n        return False\n\n    if "use_migration_files" in signature.parameters:\n        return True\n\n    return any(\n        parameter.kind == _inspect.Parameter.VAR_KEYWORD for parameter in signature.parameters.values()\n    )\n\n\nclass BaseDBManager(LoggingMixin):\n    """Abstract Base DB manager for external DBs."""\n\n    metadata: MetaData\n    migration_dir: str\n    alembic_file: str\n    version_table_name: str\n    # Whether the database supports dropping tables when airflow tables are dropped\n    supports_table_dropping: bool = False\n    revision_heads_map: dict[str, str] = {}\n\n    def __init__(self, session):\n        super().__init__()\n        self.session = session\n\n    def _release_metadata_locks_if_needed(self) -> None:\n        """\n        Release MySQL metadata locks by committing the session.\n\n        MySQL requires metadata locks to be released before DDL operations.\n        This is done by committing the current transaction.\n        This method is a no-op for non-MySQL databases.\n        """\n        if get_dialect_name(self.session) != "mysql":\n            return\n\n        self.log.debug("MySQL: Releasing metadata locks for DDL operations")\n        self.session.commit()\n        self.log.debug("MySQL: Session committed, metadata locks released")\n\n    def get_alembic_config(self):\n        from alembic.config import Config\n\n        from airflow import settings\n\n        config = Config(self.alembic_file)\n        config.set_main_option("script_location", self.migration_dir.replace("%", "%%"))\n        config.set_main_option("sqlalchemy.url", settings.SQL_ALCHEMY_CONN.replace("%", "%%"))\n        return config\n\n    def get_script_object(self, config=None) -> ScriptDirectory:\n        from alembic.script import ScriptDirectory\n\n        if not config:\n            config = self.get_alembic_config()\n        return ScriptDirectory.from_config(config)\n\n    def _get_migration_ctx(self):\n        from alembic.migration import MigrationContext\n\n        conn = self.session.connection()\n\n        return MigrationContext.configure(conn, opts={"version_table": self.version_table_name})\n\n    def get_current_revision(self):\n        return self._get_migration_ctx().get_current_revision()\n\n    def check_migration(self):\n        """Check migration done."""\n        script_heads = self.get_script_object().get_heads()\n        db_heads = self.get_current_revision()\n        if db_heads:\n            db_heads = {db_heads}\n        if not db_heads and not script_heads:\n            return True\n        if set(script_heads) == db_heads:\n            return True\n        return False\n\n    def create_db_from_orm(self):\n        """Create database from ORM."""\n        self.log.info("Creating %s tables from the ORM", self.__class__.__name__)\n        self._release_metadata_locks_if_needed()\n        engine = self.session.get_bind().engine\n        self.metadata.create_all(engine)\n        config = self.get_alembic_config()\n        command.stamp(config, "head")\n        self.log.info("%s tables have been created from the ORM", self.__class__.__name__)\n\n    def drop_tables(self, connection):\n        if not self.supports_table_dropping:\n            return\n        self.metadata.drop_all(connection)\n        version = self._get_migration_ctx()._version\n        if inspect(connection).has_table(version.name):\n            version.drop(connection)\n\n    def resetdb(self, skip_init=False, use_migration_files=False):\n        from airflow.utils.db import DBLocks, create_global_lock\n\n        self._release_metadata_locks_if_needed()\n\n        connection = settings.engine.connect()\n\n        with create_global_lock(self.session, lock=DBLocks.MIGRATIONS), connection.begin():\n            self.log.info("Dropping %s tables", self.__class__.__name__)\n            self.drop_tables(connection)\n        if not skip_init:\n            if _callable_accepts_use_migration_files(self.initdb):\n                self.initdb(use_migration_files=use_migration_files)\n            else:\n                self.initdb()\n\n    def initdb(self, use_migration_files=False):\n        """Initialize the database."""\n        self._release_metadata_locks_if_needed()\n        db_exists = self.get_current_revision()\n        if db_exists or use_migration_files:\n            if _callable_accepts_use_migration_files(self.upgradedb):\n                self.upgradedb(use_migration_files=use_migration_files)\n            else:\n                self.upgradedb()\n        else:\n            self.create_db_from_orm()\n\n    def upgradedb(self, to_revision=None, from_revision=None, show_sql_only=False, use_migration_files=False):\n        """Upgrade the database."""\n        self.log.info("Upgrading the %s database", self.__class__.__name__)\n\n        self._release_metadata_locks_if_needed()\n        current_revision = self.get_current_revision()\n        # MySQL can reacquire metadata locks during the revision lookup above.\n        # Release them again before Alembic opens its migration connection.\n        self._release_metadata_locks_if_needed()\n\n        if not current_revision and not to_revision and not use_migration_files and not show_sql_only:\n            self.create_db_from_orm()\n            return\n\n        config = self.get_alembic_config()\n        command.upgrade(config, revision=to_revision or "heads", sql=show_sql_only)\n        self.log.info("Migrated the %s database", self.__class__.__name__)\n\n    def downgrade(self, to_revision, from_revision=None, show_sql_only=False):\n        """Downgrade the database."""\n        raise NotImplementedError\n\n\nclass RunDBManager(LoggingMixin):\n    """\n    Run External DB Managers.\n\n    Validates and runs the external database managers.\n    """\n\n    def __init__(self):\n        from airflow.api_fastapi.app import create_auth_manager\n        from airflow.providers_manager import ProvidersManager\n\n        super().__init__()\n        self._managers: list[BaseDBManager] = []\n\n        # Start with auto-discovered DB managers from installed providers\n        managers: list[str] = list(ProvidersManager().db_managers)\n\n        # Add any explicitly configured managers not already discovered\n        managers_config = conf.get("database", "external_db_managers", fallback=None)\n        if managers_config:\n            for m in managers_config.split(","):\n                if stripped := m.strip():\n                    if stripped not in managers:\n                        managers.append(stripped)\n\n        # Add DB manager declared by the configured auth manager (existing behavior, deduplicated)\n        auth_manager_db_manager = create_auth_manager().get_db_manager()\n        if auth_manager_db_manager and auth_manager_db_manager not in managers:\n            managers.append(auth_manager_db_manager)\n\n        for module in managers:\n            manager = import_string(module.strip())\n            self._managers.append(manager)\n\n    def validate(self):\n        """Validate the external database managers."""\n        for manager in self._managers:\n            RunDBManager._validate(manager)\n\n    @staticmethod\n    def _validate(manager: BaseDBManager):\n        """Validate the external database migration."""\n        import ast\n\n        from airflow.models.base import metadata as airflow_metadata\n\n        external_metadata = manager.metadata\n        airflow_m = airflow_metadata\n        # validate tables are not airflow tables in metadata\n        for table_ in external_metadata.tables:\n            if table_ in airflow_m.tables:\n                raise AirflowException(f"Table \'{table_}\' already exists in the Airflow metadata")\n        # validate the version table schema is set appropriately in env.py\n        migration_dir = manager.migration_dir\n        env_file = os.path.join(migration_dir, "env.py")\n        with open(env_file) as f:\n            tree = ast.parse(f.read(), filename=env_file)\n\n        for node in ast.walk(tree):\n            if (\n                isinstance(node, ast.Call)\n                and isinstance(node.func, ast.Name)\n                and node.func.id == "context.configure"\n            ):\n                if "version_table" not in node.keywords:\n                    raise AirflowException(f"version_table not set in {env_file}")\n        # validate the version table is not airflow version table\n        if manager.version_table_name == "alembic_version":\n            raise AirflowException(f"{manager}.version_table_name cannot be \'alembic_version\'")\n\n    def check_migration(self, session):\n        """Check the external database migration."""\n        return_value = []\n        for manager in self._managers:\n            m = manager(session)\n            return_value.append(m.check_migration)\n        return all([x() for x in return_value])\n\n    def _call_with_optional_use_migration_files(\n        self, manager_instance: BaseDBManager, method_name: str, use_migration_files: bool\n    ) -> None:\n        method = getattr(manager_instance, method_name)\n        if _callable_accepts_use_migration_files(method):\n            method(use_migration_files=use_migration_files)\n            return\n\n        if use_migration_files:\n            self.log.warning(\n                "External DB manager %s.%s does not support \'use_migration_files\'; proceeding without it.",\n                type(manager_instance).__name__,\n                method_name,\n            )\n        method()\n\n    def initdb(self, session, use_migration_files=False):\n        """Initialize the external database managers."""\n        for manager in self._managers:\n            m = manager(session)\n            self._call_with_optional_use_migration_files(m, "initdb", use_migration_files)\n\n    def upgradedb(self, session, use_migration_files=False):\n        """Upgrade the external database managers."""\n        for manager in self._managers:\n            m = manager(session)\n            self._call_with_optional_use_migration_files(m, "upgradedb", use_migration_files)\n\n    def drop_tables(self, session, connection):\n        """Drop the external database managers."""\n        for manager in self._managers:\n            m = manager(session)\n            m.drop_tables(connection)\n',
            'airflow-core/tests/unit/utils/test_db_manager.py': '# Licensed to the Apache Software Foundation (ASF) under one\n# or more contributor license agreements.  See the NOTICE file\n# distributed with this work for additional information\n# regarding copyright ownership.  The ASF licenses this file\n# to you under the Apache License, Version 2.0 (the\n# "License"); you may not use this file except in compliance\n# with the License.  You may obtain a copy of the License at\n#\n#   http://www.apache.org/licenses/LICENSE-2.0\n#\n# Unless required by applicable law or agreed to in writing,\n# software distributed under the License is distributed on an\n# "AS IS" BASIS, WITHOUT WARRANTIES OR CONDITIONS OF ANY\n# KIND, either express or implied.  See the License for the\n# specific language governing permissions and limitations\n# under the License.\nfrom __future__ import annotations\n\nfrom contextlib import nullcontext\nfrom unittest import mock\n\nimport pytest\n\nfrom airflow.models import Base\nfrom airflow.utils.db_manager import BaseDBManager, RunDBManager\n\npytestmark = [pytest.mark.db_test]\n\n\nclass MockDBManager(BaseDBManager):\n    metadata = Base.metadata\n    version_table_name = "mock_alembic_version"\n    migration_dir = "mock_migration_dir"\n    alembic_file = "mock_alembic.ini"\n    supports_table_dropping = True\n\n\nclass CustomDBManager(BaseDBManager):\n    metadata = Base.metadata\n    version_table_name = "custom_alembic_version"\n    migration_dir = "custom_migration_dir"\n    alembic_file = "custom_alembic.ini"\n\n    def downgrade(self, to_revision, from_revision=None, show_sql_only=False):\n        from alembic import command as alembic_command\n\n        config = self.get_alembic_config()\n        alembic_command.downgrade(config, revision=to_revision, sql=show_sql_only)\n\n\nclass LegacySignatureExternalManager:\n    initdb_calls = 0\n    upgradedb_calls = 0\n\n    def __init__(self, _session):\n        pass\n\n    def initdb(self):\n        type(self).initdb_calls += 1\n\n    def upgradedb(self):\n        type(self).upgradedb_calls += 1\n\n\nclass ExplicitKwargExternalManager:\n    initdb_kwargs: list[bool] = []\n    upgradedb_kwargs: list[bool] = []\n\n    def __init__(self, _session):\n        pass\n\n    def initdb(self, use_migration_files=False):\n        type(self).initdb_kwargs.append(use_migration_files)\n\n    def upgradedb(self, use_migration_files=False):\n        type(self).upgradedb_kwargs.append(use_migration_files)\n\n\nclass VarKwargExternalManager:\n    initdb_kwargs: list[dict] = []\n    upgradedb_kwargs: list[dict] = []\n\n    def __init__(self, _session):\n        pass\n\n    def initdb(self, **kwargs):\n        type(self).initdb_kwargs.append(kwargs)\n\n    def upgradedb(self, **kwargs):\n        type(self).upgradedb_kwargs.append(kwargs)\n\n\ndef _create_run_db_manager(*managers):\n    run_db_manager = RunDBManager.__new__(RunDBManager)\n    run_db_manager._managers = list(managers)\n    return run_db_manager\n\n\nclass TestBaseDBManager:\n    @mock.patch.object(BaseDBManager, "get_alembic_config")\n    @mock.patch.object(BaseDBManager, "get_current_revision")\n    @mock.patch.object(BaseDBManager, "create_db_from_orm")\n    def test_create_db_from_orm_called_from_init(\n        self, mock_create_db_from_orm, mock_current_revision, mock_config, session\n    ):\n        mock_current_revision.return_value = None\n\n        manager = MockDBManager(session)\n        manager.initdb()\n        mock_create_db_from_orm.assert_called_once()\n\n    @mock.patch.object(BaseDBManager, "upgradedb")\n    @mock.patch.object(BaseDBManager, "get_current_revision")\n    def test_initdb_use_migration_files_calls_upgrade(self, mock_current_revision, mock_upgradedb, session):\n        mock_current_revision.return_value = None\n\n        manager = MockDBManager(session)\n        manager.initdb(use_migration_files=True)\n\n        mock_upgradedb.assert_called_once_with(use_migration_files=True)\n\n    @mock.patch.object(BaseDBManager, "get_alembic_config")\n    @mock.patch("alembic.command.upgrade")\n    @mock.patch.object(BaseDBManager, "get_current_revision")\n    def test_upgrade(self, mock_current_revision, mock_alembic_cmd, mock_alembic_config, session, caplog):\n        mock_current_revision.return_value = "current-revision"\n        manager = MockDBManager(session)\n        manager.upgradedb()\n        mock_alembic_cmd.assert_called_once()\n        assert "Upgrading the MockDBManager database" in caplog.text\n\n    @mock.patch.object(BaseDBManager, "create_db_from_orm")\n    @mock.patch.object(BaseDBManager, "get_current_revision")\n    def test_upgrade_empty_db_without_migration_files_uses_create_db_from_orm(\n        self, mock_current_revision, mock_create_db_from_orm, session\n    ):\n        mock_current_revision.return_value = None\n        manager = MockDBManager(session)\n        manager.upgradedb()\n        mock_create_db_from_orm.assert_called_once()\n\n    @mock.patch.object(BaseDBManager, "get_script_object")\n    @mock.patch.object(BaseDBManager, "get_current_revision")\n    def test_check_migration(self, mock_script_obj, mock_current_revision, session):\n        manager = MockDBManager(session)\n        manager.check_migration()  # just ensure this can be called\n\n    def test_custom_db_manager_downgrade_uses_revision_kwarg(self, session):\n        manager = CustomDBManager(session)\n        with (\n            mock.patch.object(BaseDBManager, "get_alembic_config") as mock_config,\n            mock.patch("alembic.command.downgrade") as mock_alembic_downgrade,\n        ):\n            cfg = object()\n            mock_config.return_value = cfg\n            manager.downgrade(to_revision="abc123", show_sql_only=True)\n            mock_alembic_downgrade.assert_called_once_with(cfg, revision="abc123", sql=True)\n\n    def test_custom_db_manager_downgrade_rejects_to_version_kwarg(self, session):\n        manager = CustomDBManager(session)\n        with pytest.raises(TypeError):\n            # Ensure the old kwarg name is not accepted anymore\n            manager.downgrade(to_version="1.2.3")  # type: ignore[call-arg]\n\n    @mock.patch("airflow.utils.db.create_global_lock", return_value=nullcontext())\n    @mock.patch.object(MockDBManager, "drop_tables")\n    @mock.patch("airflow.utils.db_manager.settings.engine.connect")\n    def test_resetdb_supports_legacy_initdb_override(\n        self, mock_connect, mock_drop_tables, mock_create_global_lock, session\n    ):\n        class LegacyInitOverrideManager(MockDBManager):\n            initdb_calls = 0\n\n            def initdb(self):\n                type(self).initdb_calls += 1\n\n        LegacyInitOverrideManager.initdb_calls = 0\n        mock_connect.return_value.begin.return_value = nullcontext()\n\n        manager = LegacyInitOverrideManager(session)\n        manager.resetdb(use_migration_files=True)\n\n        assert LegacyInitOverrideManager.initdb_calls == 1\n        mock_drop_tables.assert_called_once()\n\n    @mock.patch.object(MockDBManager, "create_db_from_orm")\n    @mock.patch.object(MockDBManager, "get_current_revision", return_value=None)\n    def test_initdb_supports_legacy_upgradedb_override(\n        self, mock_get_current_revision, mock_create_db_from_orm, session\n    ):\n        class LegacyUpgradeOverrideManager(MockDBManager):\n            upgradedb_calls = 0\n\n            def upgradedb(self, to_revision=None, from_revision=None, show_sql_only=False):\n                type(self).upgradedb_calls += 1\n\n        LegacyUpgradeOverrideManager.upgradedb_calls = 0\n\n        manager = LegacyUpgradeOverrideManager(session)\n        manager.initdb(use_migration_files=True)\n\n        assert LegacyUpgradeOverrideManager.upgradedb_calls == 1\n        mock_create_db_from_orm.assert_not_called()\n        mock_get_current_revision.assert_called_once()\n\n\nclass TestRunDBManager:\n    def test_initdb_and_upgradedb_support_legacy_manager_signatures(self, session):\n        LegacySignatureExternalManager.initdb_calls = 0\n        LegacySignatureExternalManager.upgradedb_calls = 0\n\n        run_db_manager = _create_run_db_manager(LegacySignatureExternalManager)\n        run_db_manager.initdb(session=session, use_migration_files=True)\n        run_db_manager.upgradedb(session=session, use_migration_files=True)\n\n        assert LegacySignatureExternalManager.initdb_calls == 1\n        assert LegacySignatureExternalManager.upgradedb_calls == 1\n\n    def test_initdb_and_upgradedb_pass_use_migration_files_to_explicit_kwarg_manager(self, session):\n        ExplicitKwargExternalManager.initdb_kwargs = []\n        ExplicitKwargExternalManager.upgradedb_kwargs = []\n\n        run_db_manager = _create_run_db_manager(ExplicitKwargExternalManager)\n        run_db_manager.initdb(session=session, use_migration_files=True)\n        run_db_manager.upgradedb(session=session, use_migration_files=False)\n\n        assert ExplicitKwargExternalManager.initdb_kwargs == [True]\n        assert ExplicitKwargExternalManager.upgradedb_kwargs == [False]\n\n    def test_initdb_and_upgradedb_pass_use_migration_files_to_var_kwarg_manager(self, session):\n        VarKwargExternalManager.initdb_kwargs = []\n        VarKwargExternalManager.upgradedb_kwargs = []\n\n        run_db_manager = _create_run_db_manager(VarKwargExternalManager)\n        run_db_manager.initdb(session=session, use_migration_files=True)\n        run_db_manager.upgradedb(session=session, use_migration_files=False)\n\n        assert VarKwargExternalManager.initdb_kwargs == [{"use_migration_files": True}]\n        assert VarKwargExternalManager.upgradedb_kwargs == [{"use_migration_files": False}]\n',
        }
